// ══ DEADLINE ══
const DEADLINE=new Date('2026-06-11T18:00:00Z'); // 20:00 España (CEST=UTC+2)
// DEBUG MODE ON BY DEFAULT — remove for production
function deadlinePassed(){return localStorage.getItem('debug_started')==='1'||new Date()>=DEADLINE;}
function renderDeadline(){
  const w=document.getElementById('deadline-wrap');if(!w)return;
  const diff=DEADLINE-new Date();
  if(diff<=0){
    w.innerHTML='<div class="deadline-bar deadline-closed"><span class="deadline-label">⛔ Plazo cerrado — El Mundial ha comenzado</span><span class="deadline-count dcount-closed">CERRADO</span></div>';
    const c=document.getElementById('porra-card');if(c&&!isAdmin){c.style.opacity='.5';c.style.pointerEvents='none';}
  }else{
    const d=Math.floor(diff/86400000),h=Math.floor((diff%86400000)/3600000),m=Math.floor((diff%3600000)/60000),s=Math.floor((diff%60000)/1000);
    const str=d>0?d+'d '+h+'h '+m+'m':h+'h '+m+'m '+s+'s';
    w.innerHTML='<div class="deadline-bar deadline-open"><span class="deadline-label">⏰ Cierre: <strong>11 jun 2026 · 20:00h España</strong></span><span class="deadline-count dcount-open">'+str+'</span></div>';
  }
}
setInterval(renderDeadline,1000);

