  if(el('lbl-my-bets-intro'))el('lbl-my-bets-intro').textContent=t('my_bets_intro');
  if(el('lbl-new-bet-porras'))el('lbl-new-bet-porras').textContent=t('new_bet').replace('➕ ','');
  if(el('lbl-pass'))el('lbl-pass').textContent=t('password');
  if(el('lbl-enter'))el('lbl-enter').textContent=t('enter');
  if(el('lbl-cancel'))el('lbl-cancel').textContent=t('cancel');
  if(el('lbl-muro'))el('lbl-muro').textContent=t('muro')||'Muro';
